class SensitiveDataFilter(logging.Filter):
    """Filter to redact sensitive information from log records."""

    SENSITIVE_PATTERNS = [
        "password",
        "secret",
        "token",
        "api_key",
        "authorization",
        "credit_card",
        "ssn",
    ]

    def filter(self, record):
        if isinstance(record.msg, str):
            msg_lower = record.msg.lower()
            for pattern in self.SENSITIVE_PATTERNS:
                if pattern in msg_lower:
                    record.msg = record.msg + " [REDACTED_FIELDS_PRESENT]"
                    break
        return True


class ContextFilter(logging.Filter):
    """Adds contextual information to log records."""

    def __init__(self, app_name="application", environment="production"):
        super().__init__()
        self.app_name = app_name
        self.environment = environment

    def filter(self, record):
        record.app_name = self.app_name
        record.environment = self.environment
        return True


def setup_logging(environment="production", log_level=None):
    """
    Initialize the logging configuration.

    Args:
        environment: The deployment environment (production, staging, development).
        log_level: Override the default log level for the application logger.
    """
    config = LOGGING_CONFIG.copy()

    # Adjust log levels based on environment
    if environment == "development":
        config["handlers"]["console"]["level"] = "DEBUG"
        config["loggers"]["application"]["level"] = "DEBUG"
        config["root"]["level"] = "DEBUG"
    elif environment == "staging":
        config["handlers"]["console"]["level"] = "DEBUG"
        config["loggers"]["application"]["level"] = "DEBUG"
    # production defaults are already set

    if log_level:
        config["loggers"]["application"]["level"] = log_level

    logging.config.dictConfig(config)

    # Add custom filters to all handlers
    context_filter = ContextFilter(
        app_name="application", environment=environment
    )
    sensitive_filter = SensitiveDataFilter()

    for handler_name in config["handlers"]:
        handler = logging.getHandlerByName(handler_name) if hasattr(logging, 'getHandlerByName') else None
        if handler:
            handler.addFilter(context_filter)
            handler.addFilter(sensitive_filter)

    # Fallback: add filters to the application logger directly
    app_logger = logging.getLogger("application")
    app_logger.addFilter(context_filter)
    app_logger.addFilter(sensitive_filter)

    app_logger.info(
        "Logging initialized for environment: %s", environment
    )

    return app_logger


def get_logger(name):
    """
    Get a logger instance for the given module name.

    Args:
        name: Typically __name__ of the calling module.

    Returns:
        A configured logger instance under the 'application' namespace.
    """
    if not name.startswith("application"):
        name = f"application.{name}"
    return logging.getLogger(name)


